/* MAIN CLASS */
class Homepage {
    $nav;
    $content;
    titles;
    showMore;
    salesSlider;
    navigation;
    topProducts;
    #newsInterval
    #interval;

    constructor() {
        this.$nav = $('#navigation .wrapper');
        this.$content = $('#homepage .main-content>.row>div');
        this.titles = {
            'ordersChart': 'Můj marketing',
            'categories': 'Categories',
            'products': 'TOP Sellers',
            'distributor': 'Your specialist',
            'sales': 'Actual sales',
            'search': 'Search'
        };

        this.showMore = ['documents', 'orders', 'latest-search'];
        this.salesSlider = null;
        this.navigation = null;
        this.topProducts = null;
        this.#interval = 10000;

    }

    init() {
        this.buildMenu();
        this.salesSlider = new SalesSlider();
        this.navigation = new Navigation();
        this.topProducts = new TopProducts();
        this.search = new Search();
        this.graphs = new GraphChange();

        this.handleNews();


        this.showMore.forEach((i) => {
            this.handleMore(i);
        });

        $('#contact .person .person-card').mousedown((e) => {
            e.preventDefault();
            $(e.target).parents('.people').find('.person .content').slideUp(300);
            $(e.target).parents('.person').find('.content').stop().slideDown(300);
        })

        $('#contact .person .content .close').click((e) => {
            $(e.target).parents('.content').stop().slideUp(300);
        })

        $('.counter').each(function () {
            $(this).prop('Counter',0).animate({
                Counter: $(this).text()
            }, {
                duration: 4000,
                easing: 'swing',
                step: function (now) {
                    $(this).text(Helpers.numberFormat(Math.ceil(now), 0, ',', ' '));
                }
            });
        });

        this.#newsInterval = setInterval(() =>{
            this.handleNews();
        },this.#interval);

        $('#otherInfo .news').mouseenter(() => {
            clearInterval(this.#newsInterval);
        }).mouseleave(() => {
            this.#newsInterval = setInterval(() =>{
                this.handleNews();
            },this.#interval);
        });

    }

    buildMenu() {
        var exclude = ['search', 'facts', 'gallery'];
        if (this.$nav.length > 0 && this.$content.length > 0) {
            this.$nav.html('');
            this.$content.each((i) => {
                if($(this.$content.get(i)).attr('id').length > 0) {
                    if(exclude.includes($(this.$content.get(i)).attr('id')) == false) {
                        var danger = ($(this.$content.get(i)).data('danger') == true)? '<i class="ci ci-warning text-danger mr-2"></i>':'';
                        this.$nav.append('<li><a href="#" data-id="' + $(this.$content.get(i)).attr('id') + '">' + danger + 
                            ((this.titles[$(this.$content.get(i)).attr('id')])?
                                (this.titles[$(this.$content.get(i)).attr('id')]):
                                ($(this.$content.get(i)).find('.title').text() + $(this.$content.get(i)).find('.panel>.heading').text())
                            ) + (($(this.$content.get(i)).data('icon'))?('<i class="' + $(this.$content.get(i)).data('icon') + '"></i>'):('<i class="far fa-circle" style="font-size: 10px;width:16px;text-align:right;"></i>')) + '</a></li>');
                    } else if($(this.$content.get(i)).attr('id') == 'search') {
                        this.$nav.append('<li><a href="#" class="search" data-id="search">' +
                        ((this.titles[$(this.$content.get(i)).attr('id')])?this.titles[$(this.$content.get(i)).attr('id')]:'Search')+ '<i class="ci ci-search"></i></a>');
                    }
                }
            });
        }
    }

    handleMore(id) {
        $('#' + id + ' .more').click(function(e) {
            e.preventDefault();
            $(e.target).parents('#' + id).toggleClass('opened');
        });
    }

    handleNews(prev = false) {
        var $news = $('#otherInfo .news .articles .article');
        var $active = $('#otherInfo .news .article-active');
        var $current = $('#otherInfo .news .control .current');

        var max_height = 0;

        $news.each(function(el) {
            $(this).parent().show();
            let height = $(this).outerHeight() + 5;
            $(this).parent().hide();
            if (height > max_height) {
                max_height = height;
            }
        })
        $active.css('min-height', max_height);

        if ($active.data('index') == undefined) {
            $active.html($news.first().html());
            $active.data('index', $news.first().data('index'));
            $current.text($active.data('index')+1);
            return;
        } else {
            $news.each(function() {
                if ($(this).data('index') == $active.data('index')) {
                    var next;
                    if (prev) {
                        next = $(this).prev('.article');
                    } else {
                        next = $(this).next('.article');
                    }
                    if ($(next).length == 0) {
                        if (prev) {
                            next = $news.last();
                        } else {
                            next = $news.first();
                        }
                    }
                    $active.html(next.html());
                    $active.data('index', next.data('index'));
                    $current.text($active.data('index')+1)
                    return false;
                }
            });
        }
    }

}

/* SLIDER FOR ACTUAL SALES */
class SalesSlider {
    slide;
    isSliding;
    slideout;
    slideprev;
    time;
    items;
    slidetime;

    constructor(slidetime = 300) {
        this.slide = null;
        this.isSliding = false;
        this.slideout = false;
        this.slideprev = false;
        this.time = 0;

        this.items = 0;
        this.slidetime = slidetime;
        this.getItemsCount();

        this.init();
    }

    getItemsCount() {
        this.items = $('#sales').find('.product').length;
        return this.items;
    }

    init(time = 10000) {
        this.time = time;
        if (this.items > 0) {
            // var random = Math.floor((Math.random() * this.items));
            // $('#sales').find('.product').eq(random).addClass('active');
            $('#sales').find('.product').eq(0).addClass('active');
        }
        
        if (this.items > 1) {
            $('#sales .control').css('display', 'flex');
            this.slideAuto();
        }

        
        $('#sales .control').find('.next, .prev').click((e) => {
            this.handleSwitch(e)
        });

        $('#sales .products').mouseenter(() => {
            this.handleMouseEnter()
        }).mouseleave(() => {
            this.handleMouseLeave()
        });
        return this;
    }

    handleSwitch(e) {
        e.preventDefault();

        if (this.isSliding == true) {
            clearTimeout(this.slide);
            this.slideAuto();
        }

        if ($(e.target).is('.prev')) {
            this.slideNext(true);
        } else {
            this.slideNext();
        }
        return;
    }

    handleMouseEnter() {
        if (this.isSliding) {
            clearTimeout(this.slide);
        }
        return;
    }

    handleMouseLeave() {
        if (this.isSliding) {
            this.slideAuto();
        }
        return;
    }

    slideAuto() {
        if(this.time > 0) {
            this.isSliding = true;
            this.slide = setTimeout(() => {
                this.slideNext();
                this.slideAuto();
            }, this.time);
        } else {
            this.isSliding = false;
            clearTimeout(this.slide);
        }
        return;
    }

    slideNext(prev = false) {
        if (this.slideout == true || this.slideprev == true) {
            return;
        }

        var active = $('#sales .products .product.active');
        var next = active.next();
        if (prev === true) {
            next = active.prev();
            if (next.length == 0) {
                next = $('#sales .products .product').last();
            }
        } else {
            if (next.length == 0) {
                next = $('#sales .products .product').first();
            }
        }
        active.addClass('slideout');
        if (prev) {
            active.addClass('prev');
            next.addClass('prev');
        }
        active.removeClass('active');
        
        this.slideout = true;
        setTimeout(() => {
            this.slideout = false;
            active.removeClass('slideout');
            active.removeClass('prev');
            next.addClass('active');
            if (prev) {
                next.addClass('prev');
                this.slideprev = true;
                setTimeout(() => {
                    this.slideprev = false;
                    next.removeClass('prev');
                }, this.slidetime);
            }
        }, this.slidetime);
        return;
    }


}

/* NAVIGATION ANIMATION */
class Navigation {
    constructor() {
        this.init();
    }

    init() {
        $(window).scroll((e) => {
            this.setItem();
        });
    }

    setItem() {
        var scrollTop = $(window).scrollTop() + ($(window).height() / 2);
        var items = [];
        $('.main-content>.row>div').each(function (i) {
            var offset = $(this).offset().top - 12;
            var offset_bottom = offset + $(this).height() + 12;
            if(offset <= scrollTop && offset_bottom >= scrollTop) {
                items.push($('#navigation li a[data-id="' + $(this).attr('id') + '"]'));
            }
        });
        $('#navigation li a').removeClass('active');
        for (var i=0;i<items.length;i++) {
            Object.values(items)[i].addClass('active');
        }
    }

}

/* TOP PRODUCTS */
class TopProducts {
    #timer;
    $products;
    productsId;
    #interval;

    constructor(productsId = 'products', interval = 300) {
        this.#timer = null;
        this.productsId = productsId;
        this.$products = $('#' + this.productsId + ' .products');
        this.#interval = interval;

        this.init();
    }

    init() {
        if(!$('#' + this.productsId + ' .category').is('.active')) {
            $('#' + this.productsId + ' .category').first().addClass('active');
            this.getData($('#' + this.productsId + ' .type.active').data('id'), $('#' + this.productsId + ' .category.active').data('id'))
        }

        this.categoryHandle();
        this.typeHandle();
    }

    categoryHandle() {
        $('#' + this.productsId + ' .category').click((e) => {
            e.preventDefault();
            
            if ($('#' + this.productsId + '').hasClass('disabled')) {
                return;
            }
        
            var active_type = $('#' + this.productsId + ' .type.active').data('id');
            $('#' + this.productsId + ' .category').removeClass('active');
            $(e.target).parents('.category').addClass('active');
            this.getData(active_type, $(e.target).parents('.category').data('id'));
        });
    }

    typeHandle() {
        $('#' + this.productsId + ' .type').click((e) => {
            e.preventDefault();
            var $type = $(e.target).parent();
            
            if ($('#' + this.productsId + '').hasClass('disabled')) {
                return;
            }
        
            var active_cat = $('#' + this.productsId + ' .category.active').data('id');
            $('#' + this.productsId + ' .type').removeClass('active');
        
            if ($(e.target).is('a')) {
                $type.addClass('active');
            } else if($(e.target).is('.right')) {
                $type.next().addClass('active');
            } else if($(e.target).is('.left')) {
                $type.prev().addClass('active');
            }
            this.getData($('#' + this.productsId + ' .type.active').data('id'), active_cat);
        });
    }

    getData(type, category) {
        var now = Date.now();
        var dt = 0;
        this.$products.addClass('slideout');
        this.$products.removeClass('active');
        $('#products').addClass('disabled');

        this.timer = setTimeout(() => {
            $.get(basePath + '/default/homepage/get-products', { type: type, category: category }).done((data) => {
                try {
                    data = JSON.parse(data);
                    dt = Date.now() - now;
                    this.$products.html('');
                    Object.keys(data).forEach((i) => {
                        if (i != 'label') {
                            this.$products.append(`<a href="${ basePath}/product/index?search=${ data[i]['Code']}" class="product"> <div class="thumb"> <img src="${ data[i]['Image']}"> <div class="overlay"> <span class="ci ci-search"></span> </div> </div> <p>${ data[i]['Name']}</p> </a>`);
                        }
                    });
                    $('#exportProducts').attr('href', basePath + '/homepage/export-top-products?category=' + data['label']);
                    
                    if (this.$products.html().length == 0) {
                        this.$products.append('<p class="text-nothing text-center w-100 font-bold h-100 d-flex align-items-center justify-content-center">' + translations.NO_PRODUCT_IN_CATEGORY + '</p>');
                    }
                } catch(ex) {
                    return;
                }
            }).always(() => {
                this.$products.removeClass('slideout');
                $('#' + this.productsId).removeClass('disabled');
                this.$products.addClass('active');
            });
        },(dt>300)?0:this.#interval);
    }
}

/* AJAX SEARCH */
class Search {
    #$search_input;
    #$search_results;
    #$result_items;
    #$result_count;
    #$link;
    cols;
    notFound;
    loading;
    dialogTitle;

    constructor(result_count = 5) {
        this.#$search_input = $('#search input');
        this.#$search_results = $('#search .search-results');
        this.#$result_items = this.#$search_results.find('.table-items');
        this.#$result_count = this.#$search_results.find('.show-more .count');
        this.#$link = this.#$search_results.find('.show-more a');
        this.cols = 6;
        this.notFound = 'No products found';
        this.loading = 'Loading...'
        this.dialogTitle = 'Product detail'

        this.link = basePath + '/product/index?search=';

        this.handleInput();
    }

    toggleResults(show = null) {
        if (show === true) {
            this.#$search_results.stop().slideDown(300);
        } else if (show === false) {
            this.#$search_results.stop().slideUp(300);
        } else {
            this.#$search_results.stop().slideToggle(300);
        }
    }

    buildItem(item, show = [true,true,true,true]) {
        let out = '';
        out += `<tr><td class="photo"><img src="${item.Photo}"></td>`;
        out += `<td>${item.Name}</td>`;
        if (show[0]) {
            out += `<td class="stock"> <span class="avai1${(item.Availability1 > 0)?'':' empty'}">${(item.Availability1 > 0)?item.Availability1:0}</span></td>`;
        }
        if (show[1]) {
            out += `<td class="stock"> <span class="avai2${(item.Availability2 > 0)?'':' empty'}">${(item.Availability2 > 0)?item.Availability2:0}</span></td>`;
        }
        if (show[2]) {
            out += `<td class="stock"> <span class="avai3${(item.Availability3 > 0)?'':' empty'}">${(item.Availability3 > 0)?item.Availability3:0}</span></td>`;
        }
        if (show[3]) {
            out += `<td class="stock">${(item.Price/100).toLocaleString()} ${item.Label}</td>`;
            out += `<td class="stock">${(item.Deposit/100).toLocaleString()} ${item.Label}</td>`;
        }
        
        out += `<td class="link"><a href="javascript: cdb.modules.homepage.search.showDetailDialog(${item.ID}, ${item.Price}, ${item.Deposit});"><i class="ci ci-search"></i></a></td></tr>`;
        return out;
    }

    buildNotFound() {
        return `<tr>
            <td colspan="${this.cols}" class="text-center"><span class="text-muted">${this.notFound}</span></td>
        </tr>`;
    }

    buildLoading() {
        return `<tr>
            <td colspan="${this.cols}" class="text-center"><span class="text-muted">${this.loading}</span></td>
        </tr>`;
    }

    processItems(items, count = 0, show = [true,true,true,true]) {
        let output = '';

        this.#$result_count.text(count);

        items.forEach((item) => {
            output += this.buildItem(item, show);
        });

        if (output.length == 0) {
            output = this.buildNotFound();
        }

        return output;
    }

    getItems(SearchString, Category = 0) {
        if (SearchString.length == 0 || $(window).width() < 769) {
            return false;
        }

        this.#$result_items.html(this.buildLoading());
        this.#$link.attr('href', this.link+SearchString);

        $.ajax({
            url: basePath + '/homepage/search-products',
            data: {
                SearchString: SearchString,
                Category: Category
            },
            success: (data) => {
                try {
                    data = JSON.parse(data);
                    this.#$result_items.html(this.processItems(data.Items, data.Count, data.Show));
                } catch (e) {
                    this.#$result_items.html(this.processItems([],0));
                }
            },
            fail: () => {
                this.#$result_items.html(this.processItems([],0));
            }
        })
    }

    searchItems(SearchString) {
        SearchString = SearchString.toLowerCase();
        if (SearchString.length > 0) {
            this.getItems(SearchString);
            if (this.#$search_results.is(':not(:visible)')) {
                this.toggleResults(true);
            }
        } else {
            this.toggleResults(false);
            this.#$result_items.html('');
        }
    }

    

    showDetailDialog(ID, Price, Deposit) {
        var dialog = new Dialog();
        dialog.title = this.dialogTitle;
        dialog.showFromUrl(basePath+'/default/product/product-detail', {
            Product_ID: ID,
            deposit: Deposit,
            price: Price,
        })
    }

    handleInput() {
        let timeout = null;

        this.#$search_input.on('keyup paste' ,(e) => {
            if (e.target.value.length > 3) {
                clearTimeout(timeout);
                timeout = setTimeout(() => {
                    this.searchItems(e.target.value);
                }, 500);
            } else {
                this.searchItems('');
            }
        });
    }

    clearInput() {
        this.#$search_input.val('');
        this.searchItems('');
    }
}

class GraphChange {
    #interval;
    #$panel;

    constructor(time = 30000) {
        this.#$panel = $('#ordersChart');
        this.$graphs = this.#$panel.find('.charts');
        this.#interval = null;
        this.time = time;

        this.init();
    }

    init() {
        this.startSliding();

        this.#$panel.mouseenter(() => {
            this.stopSliding();
        }).mouseleave((e) => {
            this.startSliding();
        });
    }

    startSliding() {
        this.#interval = setInterval(() => {
            this.changeGraph();
        }, this.time);
    }

    stopSliding() {
        clearInterval(this.#interval);
        this.#interval = null;
    }

    changeGraph(prev = false) {
        let active = this.$graphs.find('.active');
        let next_chart = prev===false?active.next():active.prev();

        if (next_chart.length === 0) {
            next_chart = prev===false?this.$graphs.find('.wrapper').first():this.$graphs.find('.wrapper').last()
        }

        if (next_chart.length === 0) {
            return false;
        }

        next_chart.addClass('active');
        active.removeClass('active');
        this.#$panel.find('.title').text(next_chart.data('title'));
    }
}